// src/types.ts
export enum TrackType {
    CLICK = 'click',
    EXPOSURE = 'exposure',
    PAGE_STAY = 'page_stay',
    CUSTOM = 'custom',
    FIRST_RENDER = 'first_render',
}

export interface TrackParams {
    eventName: string;
    type: TrackType;
    [key: string]: any;
}

// 全局配置类型
export interface TrackGlobalConfig {
    // 埋点上报接口 URL
    trackUrl: string;
    // 批量上报接口 URL
    batchTrackUrl?: string;
    // 是否开启埋点
    enable?: boolean;
    // 是否开启批量上报
    enableBatch?: boolean
    // 重试配置
    retryConfig?: {
        maxRetryTimes: number;
        initialDelay: number;
        delayMultiplier: number;
    };
    // 批量上报配置
    batchConfig?: {
        batchSize: number, // 队列容量上限
        batchInterval: number, // 触发上报间隔
    }
    // 曝光埋点配置
    exposureConfig?: {
        exposureOnce?: boolean; // 暴露是否只触发一次
        exposureThreshold?: number; // 元素暴露多少部分（0-1）触发
    }
    // 页面停留配置
    pageStayConfig?: {
        timeout?: number; // 多少时间不操作，就暂停计时，并进行埋点上报
        minDuration?: number; // 最短有效时间
        maxDuration?: number; // 最长单次计时（防止数据异常）
        checkInterval?: number; // 多长时间检查一次用户无操作时间
        reportOnHidden?: boolean; // 是否在页面切后台时进行上报
    }
}

// TrackConfig 继承并扩展全局配置，支持单个 Hook 覆盖
export interface TrackConfig extends Partial<TrackGlobalConfig> {
    exposureOnce?: boolean; // 曝光埋点仅生效一次
    exposureThreshold?: number; // 曝光埋点的阈值
}

export interface FailedTrackParams extends TrackParams {
    retryTime: number; // 上次重试时间
    retryCount?: number; // 重试次数
}